def load_db():
    if not os.path.exists(DB_FILE):
        return []
    try:
        with open(DB_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, list) else []
    except Exception:
        return []


def save_db(data):
    with open(DB_FILE, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def parse_float(v):
    if v is None or v == "":
        return None
    try:
        if pd.isna(v):
            return None
    except Exception:
        pass
    try:
        return float(str(v).replace(",", "."))
    except Exception:
        return None


def calc_stats(values, lie, lse, sample_groups=None):
    vals = [parse_float(v) for v in values]
    vals = [v for v in vals if v is not None]
    if len(vals) < 2:
        return None
    n = len(vals)
    mean = sum(vals) / n
    std = math.sqrt(sum((v - mean) ** 2 for v in vals) / (n - 1))
    if std == 0:
        return None
    cp = (lse - lie) / (6 * std)
    cpu = (lse - mean) / (3 * std)
    cpl = (mean - lie) / (3 * std)
    cpk = min(cpu, cpl)
    r_values = []
    if sample_groups:
        for grupo in sample_groups:
            g = [parse_float(x) for x in grupo]
            g = [x for x in g if x is not None]
            if len(g) >= 2:
                r_values.append(max(g) - min(g))
    r_bar = sum(r_values) / len(r_values) if r_values else None
    return {"n": n, "mean": mean, "std": std, "cp": cp, "cpu": cpu, "cpl": cpl, "cpk": cpk, "r_bar": r_bar, "values": vals}


def status_by_index(x):
    if x is None:
        return "Sem análise", "wn"
    if x < 1.00:
        return "Ruim / incapaz", "fl"
    if x < 1.33:
        return "Marginal / atenção", "wn"
    if x < 1.67:
        return "Bom", "ok"
    return "Excelente", "ok"


def parecer(stats, lie, lse):
    st_cpk, lvl = status_by_index(stats["cpk"])
    centro = stats["mean"]
    faixa_centro = (lie + lse) / 2
    desloc = centro - faixa_centro
    lado = "superior" if stats["cpu"] < stats["cpl"] else "inferior"
    linhas = []
    if stats["cpk"] < 1:
        linhas.append("Processo incapaz: existe risco elevado de gerar medidas fora dos limites especificados.")
    elif stats["cpk"] < 1.33:
        linhas.append("Processo marginal: atende parcialmente, mas deve ser monitorado e melhorado.")
    else:
        linhas.append("Processo capaz: os resultados indicam boa condição de atendimento à especificação.")
    if abs(desloc) > (lse - lie) * 0.05:
        linhas.append(f"A média está deslocada em relação ao centro da especificação. O lado mais crítico é o limite {lado}.")
    else:
        linhas.append("A média está próxima do centro da especificação.")
    if stats.get("r_bar") is not None:
        linhas.append(f"A variação média entre medições por amostra foi R̄={stats['r_bar']:.4f}.")
    return st_cpk, lvl, " ".join(linhas)


def make_chart(carta, stats):
    flat = []
    xs = []
    for amostra in carta["amostras"]:
        for med in amostra["medidas"]:
            flat.append(parse_float(med))
            xs.append(f"A{amostra['amostra']}")
    fig = go.Figure()
    fig.add_trace(go.Scatter(y=flat, x=list(range(1, len(flat)+1)), mode="lines+markers", name="Medições"))
    fig.add_hline(y=carta["lie"], line_dash="dash", line_color="red", annotation_text="LIE", annotation_position="top left")
    fig.add_hline(y=carta["lse"], line_dash="dash", line_color="red", annotation_text="LSE", annotation_position="top left")
    fig.update_layout(
        title=f"{carta['descricao']} | Cpk={stats['cpk']:.2f} | X̄={stats['mean']:.4f}",
        xaxis_title="Medições sequenciais",
        yaxis_title="Valor medido",
        height=420,
        margin=dict(l=40, r=30, t=70, b=40),
        showlegend=False,
        plot_bgcolor="white",
        paper_bgcolor="white",
    )
    return fig


def img_bytes():
    return base64.b64decode(MODELO_CEP_B64)


def build_pdf(carta, stats, analise_txt):
    if A4 is None:
        return None
    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=A4, leftMargin=12*mm, rightMargin=12*mm, topMargin=12*mm, bottomMargin=12*mm)
    styles = getSampleStyleSheet()
    title = ParagraphStyle("title", parent=styles["Heading1"], fontSize=16, textColor=colors.HexColor("#003b7a"), spaceAfter=8)
    h = ParagraphStyle("h", parent=styles["Heading2"], fontSize=11, textColor=colors.HexColor("#003b7a"), spaceBefore=8, spaceAfter=4)
    body = ParagraphStyle("body", parent=styles["Normal"], fontSize=8, leading=11)
    story = [Paragraph("Relatório de Análise Estatística - CEP / CPK", title)]
    story.append(Paragraph("Identificação da inspeção", h))
    ident = [
        ["Descrição", carta["descricao"], "Data/Hora", carta["data_hora"]],
        ["LIE", carta["lie"], "LSE", carta["lse"]],
        ["Amostras", carta["num_amostras"], "Medições por amostra", carta["num_medidas"]],
    ]
    t = Table(ident, colWidths=[32*mm, 68*mm, 38*mm, 48*mm])
    t.setStyle(TableStyle([("GRID",(0,0),(-1,-1),0.25,colors.grey), ("BACKGROUND",(0,0),(-1,-1),colors.whitesmoke), ("FONTNAME",(0,0),(0,-1),"Helvetica-Bold"), ("FONTNAME",(2,0),(2,-1),"Helvetica-Bold")]))
    story.append(t)
    story.append(Paragraph("Indicadores calculados", h))
    indicadores = [["Cp", f"{stats['cp']:.4f}", "Cpk", f"{stats['cpk']:.4f}"], ["CPU", f"{stats['cpu']:.4f}", "CPL", f"{stats['cpl']:.4f}"], ["X̄", f"{stats['mean']:.4f}", "R̄", f"{stats['r_bar']:.4f}" if stats.get("r_bar") is not None else "—"]]
    ti = Table(indicadores, colWidths=[25*mm, 55*mm, 25*mm, 55*mm])
    ti.setStyle(TableStyle([("GRID",(0,0),(-1,-1),0.25,colors.grey), ("FONTNAME",(0,0),(0,-1),"Helvetica-Bold"), ("FONTNAME",(2,0),(2,-1),"Helvetica-Bold")]))
    story.append(ti)
    story.append(Paragraph("Análise automática", h))
    story.append(Paragraph(analise_txt, body))
    story.append(Spacer(1, 5*mm))
    # Add image model as appendix
    story.append(Paragraph("Modelo de referência para leitura dos indicadores", h))
    imgbuf = io.BytesIO(img_bytes())
    story.append(RLImage(imgbuf, width=175*mm, height=260*mm))
    doc.build(story)
    buf.seek(0)
    return buf.getvalue()


def init():
    if "cartas" not in st.session_state:
        st.session_state.cartas = load_db()
    if "registro_salvo" not in st.session_state:
        st.session_state.registro_salvo = False
    if "nonce" not in st.session_state:
        st.session_state.nonce = 0

init()

st.title("📊 Indicadores de Capacidade do Processo - CEP / CPK")
st.caption("Registro padronizado de inspeções, cálculo automático dos indicadores e análise do status do processo.")

abas = ["Registro"]
if st.session_state.cartas:
    abas.append("Análise Estatística")
abas.append("Modelo de Cálculo")
tabs = st.tabs(abas)

with tabs[0]:
    st.markdown("<div class='block-card'>", unsafe_allow_html=True)
    st.subheader("1. Registro da inspeção")
    with st.form(f"form_registro_{st.session_state.nonce}", clear_on_submit=False):
        registro = st.selectbox("Registro pré-definido", REGISTROS_PRE_DEFINIDOS)
        if registro == "Outro registro controlado":
            registro = st.text_input("Descrição do registro controlado")
        c1, c2, c3, c4 = st.columns(4)
        with c1:
            num_amostras = st.number_input("Número de amostras", min_value=1, max_value=200, value=5, step=1)
        with c2:
            num_medidas = st.number_input("Número de medidas por amostra", min_value=1, max_value=20, value=3, step=1)
        with c3:
            lie = st.number_input("Limite mínimo permitido - LIE", value=0.0, format="%.4f")
        with c4:
            lse = st.number_input("Limite máximo permitido - LSE", value=1.0, format="%.4f")
        submitted = st.form_submit_button("Gerar tabela de coleta")
    st.markdown("</div>", unsafe_allow_html=True)

    if submitted:
        erros = []
        if not str(registro).strip():
            erros.append("Informe a descrição da inspeção.")
        if lse <= lie:
            erros.append("O limite máximo permitido deve ser maior que o limite mínimo permitido.")
        if erros:
            for e in erros:
                st.error(e)
        else:
            st.session_state.coleta_atual = {
                "descricao": str(registro).strip(),
                "num_amostras": int(num_amostras),
                "num_medidas": int(num_medidas),
                "lie": float(lie),
                "lse": float(lse),
            }
            st.session_state.registro_salvo = True

    if st.session_state.get("registro_salvo") and st.session_state.get("coleta_atual"):
        cfg = st.session_state.coleta_atual
        st.markdown("<div class='block-card'>", unsafe_allow_html=True)
        st.subheader("2. Lançamento das medições")
        st.info("Preencha todas as medições. Ao salvar, a carta será gravada com a descrição da inspeção + data e hora do sistema.")
        linhas = []
        for a in range(1, cfg["num_amostras"] + 1):
            linha = {"Amostra": a}
            for m in range(1, cfg["num_medidas"] + 1):
                linha[f"Medida {m}"] = None
            linhas.append(linha)
        df_base = pd.DataFrame(linhas)
        edited = st.data_editor(df_base, num_rows="fixed", use_container_width=True, key=f"editor_{st.session_state.nonce}")
        if st.button("Salvar carta de inspeção", type="primary"):
            amostras = []
            faltantes = 0
            fora = 0
            for _, row in edited.iterrows():
                medidas = []
                for m in range(1, cfg["num_medidas"] + 1):
                    val = parse_float(row.get(f"Medida {m}"))
                    if val is None:
                        faltantes += 1
                    else:
                        if val < cfg["lie"] or val > cfg["lse"]:
                            fora += 1
                    medidas.append(val)
                amostras.append({"amostra": int(row["Amostra"]), "medidas": medidas})
            if faltantes:
                st.error("Existem medições em branco. Preencha todas as medidas antes de salvar.")
            else:
                agora = datetime.now().strftime("%d/%m/%Y %H:%M:%S")
                carta = {
                    "id": datetime.now().strftime("%Y%m%d%H%M%S"),
                    "descricao": cfg["descricao"],
                    "nome_final": f"{cfg['descricao']} - {agora}",
                    "data_hora": agora,
                    "num_amostras": cfg["num_amostras"],
                    "num_medidas": cfg["num_medidas"],
                    "lie": cfg["lie"],
                    "lse": cfg["lse"],
                    "amostras": amostras,
                }
                st.session_state.cartas.append(carta)
                save_db(st.session_state.cartas)
                st.success("Carta de inspeção salva. Os campos serão limpos e o app retornará para Registro.")
                st.session_state.registro_salvo = False
                st.session_state.coleta_atual = None
                st.session_state.nonce += 1
                st.rerun()
        st.markdown("</div>", unsafe_allow_html=True)

if "Análise Estatística" in abas:
    idx = abas.index("Análise Estatística")
    with tabs[idx]:
        st.subheader("Análise Estatística das cartas salvas")
        cartas_validas = []
        for c in st.session_state.cartas:
            grupos = [a["medidas"] for a in c.get("amostras", [])]
            flat = [v for g in grupos for v in g]
            s = calc_stats(flat, c["lie"], c["lse"], grupos)
            if s:
                cartas_validas.append((c, s))
        if not cartas_validas:
            st.warning("Ainda não existe carta preenchida com dados suficientes para análise.")
        else:
            nomes = [c["nome_final"] for c, _ in cartas_validas]
            escolha = st.selectbox("Selecione a carta para análise", nomes)
            carta, stats = next((c, s) for c, s in cartas_validas if c["nome_final"] == escolha)
            status, nivel, texto = parecer(stats, carta["lie"], carta["lse"])
            k1, k2, k3, k4, k5 = st.columns(5)
            k1.metric("Cp", f"{stats['cp']:.3f}")
            k2.metric("CPU/CPL", f"{stats['cpu']:.3f} / {stats['cpl']:.3f}")
            k3.metric("X̄ Centro", f"{stats['mean']:.4f}")
            k4.metric("R̄ Variação", f"{stats['r_bar']:.4f}" if stats.get("r_bar") is not None else "—")
            k5.metric("Cpk", f"{stats['cpk']:.3f}")
            st.plotly_chart(make_chart(carta, stats), use_container_width=True)
            st.markdown(f"<div class='{nivel}'><b>Status:</b> {status}<br>{texto}</div>", unsafe_allow_html=True)
            with st.expander("Ver tabela de medições"):
                rows = []
                for a in carta["amostras"]:
                    row = {"Amostra": a["amostra"]}
                    for i, med in enumerate(a["medidas"], start=1):
                        row[f"Medida {i}"] = med
                    rows.append(row)
                st.dataframe(pd.DataFrame(rows), use_container_width=True)
            pdf = build_pdf(carta, stats, texto)
            if pdf:
                st.download_button("Baixar relatório PDF", data=pdf, file_name=f"relatorio_cpk_{carta['id']}.pdf", mime="application/pdf")

with tabs[-1]:
    st.subheader("Modelo de cálculo e interpretação")
    st.caption("Imagem de referência para leitura dos indicadores Cp, Cpk, Cpu/Cpl, média, amplitude e desvio padrão.")
    st.image(img_bytes(), use_container_width=True)
    with st.expander("Regras implementadas no aplicativo"):
        st.markdown("""
        - **Cp**: capacidade potencial do processo, sem considerar centralização.
        - **Cpk**: capacidade real, considerando variação e centralização.
        - **CPU/CPL**: indicam o lado crítico do processo em relação ao limite superior ou inferior.
        - **X̄**: média geral das medições coletadas.
        - **R̄**: amplitude média entre as medições dentro de cada amostra.
        - **Status**: abaixo de 1,00 = ruim/incapaz; de 1,00 a 1,33 = marginal/atenção; de 1,33 a 1,67 = bom; acima de 1,67 = excelente.
        """)
